import sympy
def A000523(n): return n.bit_length() - 1
def generate_arrival_boundary_primes(limit):
    arrival_primes = []
    p = 2
    while len(arrival_primes) < limit:
        q = sympy.nextprime(p)
        if q - p == A000523(q):
            arrival_primes.append(q)
        p = q
    return arrival_primes
